function countPairsLess(a, target) {
  let lo = 0, hi = a.length - 1, count = 0;
  while (lo < hi) {
    if (a[lo] + a[hi] < target) { count += hi - lo; lo++; }
    else hi--;
  }
  return count;
}

tests:
if (countPairsLess([1, 2, 3, 4], 5) !== 2) throw new Error('2: ' + countPairsLess([1, 2, 3, 4], 5));
if (countPairsLess([1, 1, 1], 3) !== 3) throw new Error('all under');
if (countPairsLess([5, 6, 7], 1) !== 0) throw new Error('none');
if (countPairsLess([], 10) !== 0) throw new Error('empty');
if (countPairsLess([1, 2], 4) !== 1) throw new Error('one');

