function isPalAlnum(s) {
  const alnum = c => /[a-z0-9]/i.test(c);
  let lo = 0, hi = s.length - 1;
  while (lo < hi) {
    while (lo < hi && !alnum(s[lo])) lo++;
    while (lo < hi && !alnum(s[hi])) hi--;
    if (s[lo].toLowerCase() !== s[hi].toLowerCase()) return false;
    lo++;
    hi--;
  }
  return true;
}

tests:
if (isPalAlnum('A man, a plan, a canal: Panama') !== true) throw new Error('panama');
if (isPalAlnum('race a car') !== false) throw new Error('racecar');
if (isPalAlnum('') !== true) throw new Error('empty');
if (isPalAlnum('.,') !== true) throw new Error('punct');
if (isPalAlnum('0P') !== false) throw new Error('0P');

