function reverseVowels(s) {
  const vowels = new Set('aeiouAEIOU');
  const a = s.split('');
  let lo = 0, hi = a.length - 1;
  while (lo < hi) {
    if (!vowels.has(a[lo])) lo++;
    else if (!vowels.has(a[hi])) hi--;
    else { [a[lo], a[hi]] = [a[hi], a[lo]]; lo++; hi--; }
  }
  return a.join('');
}

tests:
if (reverseVowels('hello') !== 'holle') throw new Error(reverseVowels('hello'));
if (reverseVowels('leetcode') !== 'leotcede') throw new Error(reverseVowels('leetcode'));
if (reverseVowels('abc') !== 'abc') throw new Error('single vowel');
if (reverseVowels('') !== '') throw new Error('empty');
if (reverseVowels('aA') !== 'Aa') throw new Error('case');

