function removeDupesTwo(a) {
  if (a.length <= 2) return a.length;
  let w = 2;
  for (let r = 2; r < a.length; r++) {
    if (a[r] !== a[w - 2]) { a[w] = a[r]; w++; }
  }
  return w;
}

tests:
const a = [1, 1, 1, 2, 2, 3];
const k = removeDupesTwo(a);
if (k !== 5) throw new Error('k: ' + k);
if (JSON.stringify(a.slice(0, k)) !== JSON.stringify([1, 1, 2, 2, 3])) throw new Error('prefix: ' + a.slice(0, k));
const b = [1, 1, 1, 1];
if (removeDupesTwo(b) !== 2) throw new Error('four ones');
if (removeDupesTwo([1]) !== 1) throw new Error('single');
if (removeDupesTwo([]) !== 0) throw new Error('empty');
if (removeDupesTwo([1, 2, 3]) !== 3) throw new Error('distinct');

